/**
 * Moves an actor in its current move direction.
 * @param actor The actor to move.
 * @returns True if the move was successful, false otherwise.
 * @throws {Error} If the actor's move direction is invalid.
 */
function moveActor(actor: Actor): boolean {
  if (actor.moveDir === DI_NODIR) return false;
  const tx = actor.x + actor.info.speed * xspeed[actor.moveDir];
  const ty = actor.y + actor.info.speed * yspeed[actor.moveDir];
  return tryMove(actor, tx, ty);
}
